// src/pages/ProductDetails.js
import { useParams } from "react-router-dom";
import { useState } from "react";
import products from "../data/ProductData";

function ProductDetails() {
  const { id } = useParams();
  const product = products.find((p) => p.id === parseInt(id));

  if (!product) {
    return <h2 className="text-center mt-10">Product Not Found</h2>;
  }

  // support for multiple images
  const images = [product.image, ...(product.images || [])];
  const [mainImage, setMainImage] = useState(images[0]);

  return (
    <div className="max-w-6xl mx-auto p-6 md:p-10 grid md:grid-cols-2 gap-10">
      {/* Left: Product Images */}
      <div className="flex flex-col items-center">
        {/* Main Image (responsive container) */}
        <div className="w-[250px] h-[250px] sm:w-[300px] sm:h-[300px] md:w-[350px] md:h-[350px] flex items-center justify-center border rounded-lg shadow overflow-hidden bg-white">
          <img
            src={mainImage}
            alt={product.name}
            className="w-full h-full object-contain"
          />
        </div>

        {/* Thumbnails */}
        <div className="flex gap-3 mt-4 flex-wrap justify-center">
          {images.map((img, idx) => (
            <div
              key={idx}
              className={`w-[60px] h-[60px] sm:w-[70px] sm:h-[70px] flex items-center justify-center border rounded cursor-pointer overflow-hidden bg-white ${
                mainImage === img ? "ring-2 ring-blue-500" : ""
              }`}
              onClick={() => setMainImage(img)}
            >
              <img
                src={img}
                alt={'${product.name}-${idx}'}
                className="w-full h-full object-contain"
              />
            </div>
          ))}
        </div>
      </div>

      {/* Right: Product Details */}
      <div>
        <h1 className="text-2xl md:text-3xl font-bold mb-3">{product.name}</h1>

        {/* Rating */}
        <div className="flex items-center gap-2 mb-4">
          <span className="text-orange-500 text-lg">★★★★☆</span>
          <p className="text-gray-600">({product.rating})</p>
        </div>

        {/* Description */}
        <p className="text-gray-700 leading-relaxed mb-4">
          {product.description}
        </p>

        {/* Price */}
        <div className="flex items-center gap-3 mb-4">
          <span className="text-2xl font-bold text-blue-600">
            ₹{product.offerPrice || product.price}
          </span>
          {product.offerPrice && (
            <span className="text-gray-400 line-through">₹{product.price}</span>
          )}
        </div>

        {/* Extra Info */}
        <div className="space-y-1 mb-6">
          <p>
            <strong>Brand:</strong> {product.brand || "Generic"}
          </p>
          <p>
            <strong>Color:</strong> {product.color || "Multi"}
          </p>
          <p>
            <strong>Category:</strong> {product.category}
          </p>
        </div>

        {/* Buttons */}
        <div className="flex gap-4">
          <button className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700">
            Add to Cart
          </button>
          <button className="bg-orange-500 text-white px-6 py-2 rounded-lg hover:bg-orange-600">
            Buy Now
          </button>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
